#!/usr/bin/env bash
# setup-ufw-zones-v11.sh
#
# UFW zone/profile firewall setup for multi-NIC Ubuntu/RKE2 hosts.
# v11: import/export config files, tighter RKE2 role-specific ports,
# single-node CNI suppression by default, optional kube-proxy health checks,
# and explicit Contour/Envoy VIP destination scoping.

set -euo pipefail

SCRIPT_VERSION="2026-06-25-v11-config-import-export-k8s-ports"
CONFIG_KIND_EXPECTED="ufw-zone-profile-config"
CONFIG_VERSION_EXPECTED="v11"
BACKUP_ROOT="/root/ufw-zone-backups"
CONFIG_ROOT="$BACKUP_ROOT/configs"
LOG_ROOT="/var/log/ufw-zone-setup"
SYSCTL_DROPIN="/etc/sysctl.d/99-ufw-zone-hardening.conf"

DETECTED_IFACES=(); ASSIGNED_IFACES=(); DOMAIN_IFACES=(); STORAGE_IFACES=(); RESTRICTED_IFACES=()
K8S_IFACES=(); RKE2_SERVER_IFACES=(); RKE2_AGENT_IFACES=(); RKE2_SINGLE_IFACES=()
HARBOR_IFACES=(); CUSTOM_INGRESS_IFACES=(); CONTOUR_IFACES=(); K8S_VIP_IFACES=()
declare -A IFACE_ZONE=(); declare -A IFACE_PROFILES=(); declare -A IFACE_STORAGE_OVERLAY=()
LOG_FILE=""; PROMPT_STEP=0; CONFIG_WAS_IMPORTED="no"; IMPORTED_CONFIG_FILE=""

ADMIN_SOURCES=""; DOMAIN_PROFILE="ssh-only"; STORAGE_SOURCES=""; NFS_EXTRA_MODE="none"; STORAGE_CUSTOM_SPECS=""
RESTRICTED_SOURCES=""; VIP_SOURCES=""; VIP_DESTS=""; VIP_DESTS_ANY="no"
K8S_API_SOURCES=""; K8S_NODE_SOURCES=""; K8S_SERVER_PEER_SOURCES=""; K8S_LB_HEALTHCHECK_SOURCES=""
CNI_PROFILE="none"; SINGLENODE_ENABLE_CNI="no"; NODEPORTS="no"; KUBE_PROXY_HEALTHCHECK="no"; ISTIO_PROFILE="none"
CUSTOM_INGRESS_SPECS=""; CONTOUR_SPECS="tcp/80 tcp/443"; DOCKER_CIDRS=""; DOCKER_PORTS=""; DOCKER_GUARD="no"; ROUTE_VIP="yes"

C_RESET=""; C_BOLD=""; C_DIM=""; C_RED=""; C_GREEN=""; C_YELLOW=""; C_BLUE=""; C_MAGENTA=""; C_CYAN=""
init_colors(){ if [[ -t 0 && -z "${NO_COLOR:-}" ]]; then C_RESET=$'\033[0m'; C_BOLD=$'\033[1m'; C_DIM=$'\033[2m'; C_RED=$'\033[31m'; C_GREEN=$'\033[32m'; C_YELLOW=$'\033[33m'; C_BLUE=$'\033[34m'; C_MAGENTA=$'\033[35m'; C_CYAN=$'\033[36m'; fi; }
heading(){ printf '\n%b%s%b\n' "${C_BOLD}${C_BLUE}" "$*" "$C_RESET"; }
subheading(){ printf '\n%b%s%b\n' "${C_BOLD}${C_CYAN}" "$*" "$C_RESET"; }
warn(){ printf '%bWARNING:%b %s\n' "${C_BOLD}${C_YELLOW}" "$C_RESET" "$*" >&2; }
err(){ printf '%bERROR:%b %s\n' "${C_BOLD}${C_RED}" "$C_RESET" "$*" >&2; }
info(){ printf '%b%s%b\n' "$C_GREEN" "$*" "$C_RESET"; }
step(){ PROMPT_STEP=$((PROMPT_STEP+1)); printf '\n%b--- Step %02d: %s ---%b\n' "${C_BOLD}${C_MAGENTA}" "$PROMPT_STEP" "$*" "$C_RESET" >&2; }
log(){ echo "[$(date -Is)] $*" >&2; }
run(){ log "+ $*"; "$@"; }
trim(){ local s="$*"; s="${s#"${s%%[![:space:]]*}"}"; s="${s%"${s##*[![:space:]]}"}"; printf '%s' "$s"; }
need(){ command -v "$1" >/dev/null 2>&1 || { err "Required command not found: $1"; exit 1; }; }
yesno(){ local p="$1" d="${2:-N}" r s; [[ "$d" =~ ^[Yy]$ ]] && s='[Y/n]' || s='[y/N]'; while true; do read -r -p "${C_BOLD}${p}${C_RESET} ${s}: " r; r="$(trim "$r")"; [[ -z "$r" ]] && r="$d"; case "$r" in y|Y|yes|YES|Yes) log "yes: $p"; return 0;; n|N|no|NO|No) log "no: $p"; return 1;; *) err "Please answer y or n.";; esac; done; }
contains(){ local n="$1" x; shift || true; for x in "$@"; do [[ "$x" == "$n" ]] && return 0; done; return 1; }
append(){ local a="$1" v="$2"; [[ -z "$v" ]] && return 0; eval "local c=(\"\${${a}[@]:-}\")"; contains "$v" "${c[@]}" || eval "${a}+=(\"\$v\")"; }
join(){ local IFS=' '; echo "$*"; }
norm(){ local i="$1"; echo "${i//,/ }"; }
skey(){ local s="$1"; echo "${s//[^A-Za-z0-9_]/_}"; }

need_root(){ [[ "${EUID}" -eq 0 ]] || { err "Run as root or with sudo."; exit 1; }; }
init_log(){ mkdir -p "$LOG_ROOT"; chmod 750 "$LOG_ROOT"; LOG_FILE="$LOG_ROOT/setup-ufw-zones-$(date +%Y%m%d-%H%M%S).log"; touch "$LOG_FILE"; chmod 640 "$LOG_FILE"; exec > >(tee -a "$LOG_FILE") 2>&1; heading "=== UFW Zone/Profile Setup Action Log ==="; echo "Version: $SCRIPT_VERSION"; echo "Date: $(date -Is)"; echo "Host: $(hostname -f 2>/dev/null || hostname)"; echo "Log file: $LOG_FILE"; }
list_ifaces(){ ip -o link show | awk -F': ' '{print $2}' | sed 's/@.*//' | grep -Ev '^(lo|docker[0-9]*|br-|veth|virbr|zt|tailscale|wg|tun|tap|cni|flannel|vxlan|cali|lxc|nerdctl)' | sort -u; }
discover(){ mapfile -t DETECTED_IFACES < <(list_ifaces); [[ ${#DETECTED_IFACES[@]} -gt 0 ]] || { err "No usable physical/primary interfaces detected."; exit 1; }; }
print_ifaces(){ subheading "Detected physical/primary interfaces"; local i=1 f st mac ip4; for f in "${DETECTED_IFACES[@]}"; do st="$(cat /sys/class/net/$f/operstate 2>/dev/null || echo unknown)"; mac="$(cat /sys/class/net/$f/address 2>/dev/null || echo unknown)"; ip4="$(ip -o -4 addr show dev "$f" 2>/dev/null | awk '{print $4}' | paste -sd ',' -)"; [[ -z "$ip4" ]] && ip4=no-ipv4; printf '  %b%2d)%b %-18s state=%-8s mac=%-17s ipv4=%s\n' "$C_BOLD" "$i" "$C_RESET" "$f" "$st" "$mac" "$ip4"; ((i++)); done; }

reset_model(){ ASSIGNED_IFACES=(); DOMAIN_IFACES=(); STORAGE_IFACES=(); RESTRICTED_IFACES=(); K8S_IFACES=(); RKE2_SERVER_IFACES=(); RKE2_AGENT_IFACES=(); RKE2_SINGLE_IFACES=(); HARBOR_IFACES=(); CUSTOM_INGRESS_IFACES=(); CONTOUR_IFACES=(); K8S_VIP_IFACES=(); IFACE_ZONE=(); IFACE_PROFILES=(); IFACE_STORAGE_OVERLAY=(); }
zone_of(){ case "$1" in 0) echo unassigned;; 1) echo domain_zone;; 2) echo storage_zone;; 3) echo restricted_zone;; *) echo invalid;; esac; }
prof_of(){ case "$1" in 0) echo zone-base;; 1) echo rke2-server;; 2) echo rke2-agent;; 3) echo rke2-singlenode;; 4) echo harbor-docker;; 5) echo custom-ingress;; 6) echo storage-workload;; 7) echo contour-envoy-ingress;; *) echo invalid;; esac; }
stor_of(){ case "$1" in 1) echo nfs-only;; 2) echo iscsi-only;; 3) echo nfs-iscsi;; 4) echo custom;; *) echo invalid;; esac; }
rebuild(){ DOMAIN_IFACES=(); STORAGE_IFACES=(); RESTRICTED_IFACES=(); K8S_IFACES=(); RKE2_SERVER_IFACES=(); RKE2_AGENT_IFACES=(); RKE2_SINGLE_IFACES=(); HARBOR_IFACES=(); CUSTOM_INGRESS_IFACES=(); CONTOUR_IFACES=(); local f p; for f in "${ASSIGNED_IFACES[@]}"; do case "${IFACE_ZONE[$f]:-}" in domain_zone) append DOMAIN_IFACES "$f";; storage_zone) append STORAGE_IFACES "$f";; restricted_zone) append RESTRICTED_IFACES "$f";; esac; for p in ${IFACE_PROFILES[$f]:-}; do case "$p" in rke2-server) append K8S_IFACES "$f"; append RKE2_SERVER_IFACES "$f";; rke2-agent) append K8S_IFACES "$f"; append RKE2_AGENT_IFACES "$f";; rke2-singlenode) append K8S_IFACES "$f"; append RKE2_SINGLE_IFACES "$f";; harbor-docker) append HARBOR_IFACES "$f";; custom-ingress) append CUSTOM_INGRESS_IFACES "$f";; contour-envoy-ingress) append CONTOUR_IFACES "$f";; esac; done; done; }

valid_config(){ local file="$1"; [[ -r "$file" ]] || { err "Config not readable: $file"; return 1; }; grep -q '^CONFIG_KIND="ufw-zone-profile-config"$' "$file" || { err "Missing CONFIG_KIND marker."; return 1; }; if grep -nEv '^[[:space:]]*$|^[[:space:]]*#|^[A-Za-z_][A-Za-z0-9_]*="[-A-Za-z0-9_./: ,+]*"[[:space:]]*$' "$file"; then err "Unsafe config syntax above."; return 1; fi; }
load_config(){ local file="$1" f k z p o imported; valid_config "$file" || exit 1; reset_model; source "$file"; [[ "${CONFIG_KIND:-}" == "$CONFIG_KIND_EXPECTED" ]] || { err "Config kind mismatch."; exit 1; }; imported="${ASSIGNED_IFACES:-}"; ASSIGNED_IFACES=(); for f in $imported; do append ASSIGNED_IFACES "$f"; k="$(skey "$f")"; eval "z=\${IFACE_ZONE_${k}:-unassigned}"; eval "p=\${IFACE_PROFILES_${k}:-none}"; eval "o=\${IFACE_STORAGE_OVERLAY_${k}:-}"; IFACE_ZONE[$f]="$z"; IFACE_PROFILES[$f]="$p"; [[ -n "$o" ]] && IFACE_STORAGE_OVERLAY[$f]="$o"; contains "$f" "${DETECTED_IFACES[@]}" || warn "Config references missing interface: $f"; done; rebuild; IMPORTED_CONFIG_FILE="$file"; CONFIG_WAS_IMPORTED=yes; }
maybe_import(){ step "Optional configuration import"; echo "Imported configs are reviewed before apply."; if yesno "Import a saved configuration file now?" N; then local f; read -r -p "${C_BOLD}Enter config file path:${C_RESET} " f; f="$(trim "$f")"; [[ -n "$f" ]] || { err "No file entered."; exit 1; }; load_config "$f"; return 0; fi; return 1; }
q(){ local v="${1//\"/}"; printf '"%s"' "$v"; }
save_config(){ mkdir -p "$CONFIG_ROOT"; chmod 750 "$CONFIG_ROOT"; local d="$CONFIG_ROOT/$(hostname -s)-ufw-zone-config-$(date +%Y%m%d-%H%M%S).conf" path f k latest; read -r -p "${C_BOLD}Save path [$d]:${C_RESET} " path; path="$(trim "$path")"; [[ -z "$path" ]] && path="$d"; { echo '# UFW Zone/Profile saved configuration'; echo "CONFIG_KIND=\"$CONFIG_KIND_EXPECTED\""; echo "CONFIG_VERSION=\"$CONFIG_VERSION_EXPECTED\""; echo "SCRIPT_VERSION_SAVED=\"$SCRIPT_VERSION\""; echo "HOSTNAME_HINT=\"$(hostname -f 2>/dev/null || hostname)\""; echo "ASSIGNED_IFACES=$(q "$(join "${ASSIGNED_IFACES[@]}")")"; for f in "${ASSIGNED_IFACES[@]}"; do k="$(skey "$f")"; echo "IFACE_ZONE_${k}=$(q "${IFACE_ZONE[$f]:-unassigned}")"; echo "IFACE_PROFILES_${k}=$(q "${IFACE_PROFILES[$f]:-none}")"; echo "IFACE_STORAGE_OVERLAY_${k}=$(q "${IFACE_STORAGE_OVERLAY[$f]:-}")"; done; for v in ADMIN_SOURCES DOMAIN_PROFILE STORAGE_SOURCES NFS_EXTRA_MODE STORAGE_CUSTOM_SPECS RESTRICTED_SOURCES VIP_SOURCES VIP_DESTS VIP_DESTS_ANY K8S_API_SOURCES K8S_NODE_SOURCES K8S_SERVER_PEER_SOURCES K8S_LB_HEALTHCHECK_SOURCES CNI_PROFILE SINGLENODE_ENABLE_CNI NODEPORTS KUBE_PROXY_HEALTHCHECK ISTIO_PROFILE CUSTOM_INGRESS_SPECS CONTOUR_SPECS DOCKER_CIDRS DOCKER_PORTS DOCKER_GUARD ROUTE_VIP; do eval "echo $v=\$(q \"\${$v}\")"; done; } > "$path"; chmod 600 "$path"; latest="$CONFIG_ROOT/$(hostname -s)-latest.conf"; ln -sfn "$path" "$latest"; info "Saved configuration: $path"; }

parse_cidrs(){ local in; in="$(trim "$1")"; [[ -z "$in" ]] && return 0; in="$(norm "$in")"; local x; for x in $in; do [[ "$x" == any || "$x" =~ ^([0-9]{1,3}\.){3}[0-9]{1,3}(/[0-9]{1,2})?$ || "$x" =~ ^[0-9a-fA-F:]+(/[0-9]{1,3})?$ ]] || { err "Invalid CIDR/IP: $x"; exit 1; }; echo "$x"; done; }
parse_specs(){ local in x pr po; in="$(trim "$1")"; [[ -z "$in" ]] && return 0; in="$(norm "$in")"; for x in $in; do [[ "$x" =~ ^(tcp|udp)/[0-9]+(:[0-9]+)?$ ]] || { err "Invalid port spec: $x"; exit 1; }; echo "$x"; done; }
p_cidrs(){ local p="$1" d="${2:-}" r; read -r -p "${C_BOLD}${p}${C_RESET}" r; r="$(trim "$r")"; [[ -z "$r" && -n "$d" ]] && r="$d"; parse_cidrs "$r" | paste -sd ' ' -; }
p_specs(){ local p="$1" d="${2:-}" r; read -r -p "${C_BOLD}${p}${C_RESET}" r; r="$(trim "$r")"; [[ -z "$r" && -n "$d" ]] && r="$d"; parse_specs "$r" | paste -sd ' ' -; }

read_zone(){ local f="$1" c z; while true; do step "Zone selection for $f"; echo "0) Unassigned"; echo "1) domain_zone"; echo "2) storage_zone"; echo "3) restricted_zone"; read -r -p "Zone choice [0-3]: " c; c="$(trim "$c")"; [[ -z "$c" ]] && c=0; z="$(zone_of "$c")"; [[ "$z" != invalid ]] && { echo "$z"; return; }; err "Enter 0-3."; done; }
read_storage(){ local f="$1" c o; while true; do step "Storage overlay for $f"; echo "1) NFS only"; echo "2) iSCSI only"; echo "3) NFS + iSCSI"; echo "4) Custom"; read -r -p "Storage overlay choice [1-4]: " c; o="$(stor_of "$(trim "$c")")"; [[ "$o" != invalid ]] && { echo "$o"; return; }; err "Enter 1-4."; done; }
valid_prof(){ local z="$1" p="$2"; [[ "$p" == storage-workload && "$z" != storage_zone ]] && return 1; [[ "$p" == harbor-docker && "$z" == storage_zone ]] && return 1; return 0; }
read_profiles(){ local f="$1" z="$2" in n p sel=(); while true; do step "Workload profile selection for $f ($z)"; echo "0) Zone base only"; echo "1) RKE2-Server"; echo "2) RKE2-Agent"; echo "3) RKE2-SingleNode"; echo "4) Harbor-Docker"; echo "5) Custom-Ingress"; echo "6) Storage-Workload"; echo "7) Contour-Envoy-Ingress"; read -r -p "Profile choice(s) [default: 0]: " in; in="$(trim "$in")"; [[ -z "$in" ]] && in=0; sel=(); for n in $(norm "$in"); do [[ "$n" =~ ^[0-7]$ ]] || { err "Invalid profile: $n"; continue 2; }; p="$(prof_of "$n")"; [[ "$p" == zone-base && "$in" != 0 ]] && { err "Do not combine 0 with other profiles."; continue 2; }; valid_prof "$z" "$p" || { err "$p is not valid on $z."; continue 2; }; sel+=("$p"); done; echo "${sel[*]}"; return; done; }
read_cni(){ local c; while true; do step "Primary CNI profile"; echo "0) None"; echo "1) RKE2 Canal VXLAN"; echo "2) RKE2 Canal + WireGuard"; echo "3) Calico BGP"; echo "4) Calico VXLAN"; echo "5) Flannel VXLAN"; echo "6) Cilium VXLAN/WireGuard"; read -r -p "CNI [0-6]: " c; c="$(trim "$c")"; [[ -z "$c" ]] && c=0; case "$c" in 0) echo none;; 1) echo canal-vxlan;; 2) echo canal-wireguard;; 3) echo calico-bgp;; 4) echo calico-vxlan;; 5) echo flannel-vxlan;; 6) echo cilium-vxlan-wireguard;; *) err "Enter 0-6."; continue;; esac; return; done; }
read_nfs_extra(){ local c; step "Optional advanced NFS compatibility"; echo "0) None / NFSv4 TCP only"; echo "1) UDP/2049"; echo "2) legacy NFSv3 pinned ports"; echo "3) both"; read -r -p "Advanced NFS choice [0-3, default 0]: " c; c="$(trim "$c")"; [[ -z "$c" ]] && c=0; case "$c" in 1) echo udp-only;; 2) echo legacy-v3;; 3) echo udp-legacy-v3;; *) echo none;; esac; }

collect(){ reset_model; print_ifaces; local f z p o x; for f in "${DETECTED_IFACES[@]}"; do z="$(read_zone "$f")"; IFACE_ZONE[$f]="$z"; [[ "$z" == unassigned ]] && { IFACE_PROFILES[$f]=none; continue; }; append ASSIGNED_IFACES "$f"; if [[ "$z" == storage_zone ]]; then o="$(read_storage "$f")"; IFACE_STORAGE_OVERLAY[$f]="$o"; IFACE_PROFILES[$f]=storage-workload; else p="$(read_profiles "$f" "$z")"; IFACE_PROFILES[$f]="$p"; fi; done; rebuild; ADMIN_SOURCES="$(p_cidrs "Admin/source CIDR(s), blank for any: ")"; [[ ${#DOMAIN_IFACES[@]} -gt 0 ]] && { step "Domain base"; echo "1) SSH only"; echo "2) SSH+HTTP/HTTPS"; echo "3) DC/Samba"; read -r -p "Domain profile [1-3, default 1]: " x; case "$(trim "$x")" in 2) DOMAIN_PROFILE=web;; 3) DOMAIN_PROFILE=dc;; *) DOMAIN_PROFILE=ssh-only;; esac; }; if [[ ${#STORAGE_IFACES[@]} -gt 0 ]]; then STORAGE_SOURCES="$(p_cidrs "Storage peer CIDR(s), blank for any: ")"; for f in "${STORAGE_IFACES[@]}"; do [[ "${IFACE_STORAGE_OVERLAY[$f]}" =~ nfs ]] && NFS_EXTRA_MODE="$(read_nfs_extra)"; [[ "${IFACE_STORAGE_OVERLAY[$f]}" == custom ]] && STORAGE_CUSTOM_SPECS="$(p_specs "Custom storage specs, e.g. tcp/2049 tcp/3260: ")"; done; fi; [[ ${#RESTRICTED_IFACES[@]} -gt 0 || ${#CUSTOM_INGRESS_IFACES[@]} -gt 0 || ${#CONTOUR_IFACES[@]} -gt 0 ]] && RESTRICTED_SOURCES="$(p_cidrs "Restricted/client source CIDR(s), blank for any: ")"; if [[ ${#K8S_IFACES[@]} -gt 0 ]]; then [[ ${#RKE2_SERVER_IFACES[@]} -gt 0 || ${#RKE2_SINGLE_IFACES[@]} -gt 0 ]] && K8S_API_SOURCES="$(p_cidrs "K8s API/admin CIDR(s), blank to reuse admin: " "$ADMIN_SOURCES")"; [[ ${#RKE2_SERVER_IFACES[@]} -gt 0 || ${#RKE2_AGENT_IFACES[@]} -gt 0 ]] && K8S_NODE_SOURCES="$(p_cidrs "All RKE2 node CIDR(s), used for 9345/10250/CNI: " "$ADMIN_SOURCES")"; [[ ${#RKE2_SERVER_IFACES[@]} -gt 0 ]] && K8S_SERVER_PEER_SOURCES="$(p_cidrs "RKE2 server/etcd peer CIDR(s), blank to reuse node CIDRs: " "$K8S_NODE_SOURCES")"; if [[ ${#RKE2_SERVER_IFACES[@]} -gt 0 || ${#RKE2_AGENT_IFACES[@]} -gt 0 ]]; then CNI_PROFILE="$(read_cni)"; elif [[ ${#RKE2_SINGLE_IFACES[@]} -gt 0 ]] && yesno "Single-node selected. Open CNI ports anyway for future multi-node?" N; then SINGLENODE_ENABLE_CNI=yes; K8S_NODE_SOURCES="$(p_cidrs "Future/all RKE2 node CIDR(s): " "$ADMIN_SOURCES")"; CNI_PROFILE="$(read_cni)"; fi; yesno "Allow NodePort 30000:32767?" N && NODEPORTS=yes; if yesno "Allow kube-proxy health check TCP/10256 from LB health source CIDRs?" N; then KUBE_PROXY_HEALTHCHECK=yes; K8S_LB_HEALTHCHECK_SOURCES="$(p_cidrs "LB health-check CIDR(s): ")"; fi; step "RKE2 service/ingress VIP usage"; echo "0) None"; echo "1) domain RKE2 IFs"; echo "2) restricted RKE2 IFs"; echo "3) both"; read -r -p "VIP zone choice [0-3, default 0]: " x; for f in "${K8S_IFACES[@]}"; do case "$(trim "${x:-0}")-${IFACE_ZONE[$f]}" in 1-domain_zone|3-domain_zone|2-restricted_zone|3-restricted_zone) append K8S_VIP_IFACES "$f";; esac; done; fi; if [[ ${#CUSTOM_INGRESS_IFACES[@]} -gt 0 || ${#CONTOUR_IFACES[@]} -gt 0 || ${#K8S_VIP_IFACES[@]} -gt 0 ]]; then VIP_SOURCES="$(p_cidrs "K8s VIP client source CIDR(s), blank to reuse restricted: " "$RESTRICTED_SOURCES")"; while true; do echo "1) Specific VIP destination(s) - recommended"; echo "2) Any destination - broad"; read -r -p "Destination choice [1-2]: " x; case "$(trim "$x")" in ""|1) VIP_DESTS="$(p_cidrs "K8s ingress VIP destination CIDR(s): ")"; [[ -n "$VIP_DESTS" ]] && break;; 2) yesno "Confirm any destination exposure?" N && { VIP_DESTS_ANY=yes; break; };; esac; done; [[ ${#CUSTOM_INGRESS_IFACES[@]} -gt 0 ]] && CUSTOM_INGRESS_SPECS="$(p_specs "Custom ingress specs [default tcp/443]: " "tcp/443")"; [[ ${#CONTOUR_IFACES[@]} -gt 0 ]] && CONTOUR_SPECS="$(p_specs "Contour/Envoy specs [default tcp/80 tcp/443]: " "tcp/80 tcp/443")"; [[ -n "$VIP_DESTS" ]] && yesno "Add routed allow rules for VIP destination(s)?" Y || ROUTE_VIP=no; fi; }

show_plan(){ heading "=== Planned Firewall Configuration Summary ==="; [[ "$CONFIG_WAS_IMPORTED" == yes ]] && echo "Imported config: $IMPORTED_CONFIG_FILE"; local f; for f in "${ASSIGNED_IFACES[@]}"; do printf '  %-18s zone=%-16s profiles=%-30s storage_overlay=%s\n' "$f" "${IFACE_ZONE[$f]:-}" "${IFACE_PROFILES[$f]:-}" "${IFACE_STORAGE_OVERLAY[$f]:-n/a}"; done; echo; printf '  Admin sources: %s\n' "${ADMIN_SOURCES:-any}"; printf '  API sources: %s\n' "${K8S_API_SOURCES:-not configured}"; printf '  RKE2 node sources: %s\n' "${K8S_NODE_SOURCES:-not configured}"; printf '  RKE2 server peer sources: %s\n' "${K8S_SERVER_PEER_SOURCES:-not configured}"; printf '  CNI profile: %s\n' "$CNI_PROFILE"; printf '  Single-node CNI override: %s\n' "$SINGLENODE_ENABLE_CNI"; printf '  VIP client sources: %s\n' "${VIP_SOURCES:-not configured}"; printf '  VIP destinations: %s\n' "${VIP_DESTS:-$([[ $VIP_DESTS_ANY == yes ]] && echo any-destination || echo not-configured)}"; printf '  Contour specs: %s\n' "${CONTOUR_SPECS:-none}"; printf '  Custom ingress specs: %s\n' "${CUSTOM_INGRESS_SPECS:-none}"; printf '  Storage sources: %s\n' "${STORAGE_SOURCES:-any}"; warn "This will reset existing UFW rules, then enable UFW."; }

backup(){ local d="$BACKUP_ROOT/$(date +%Y%m%d-%H%M%S)"; run mkdir -p "$d"; ufw status numbered > "$d/ufw-status-numbered-before.txt" 2>&1 || true; ufw show added > "$d/ufw-show-added-before.txt" 2>&1 || true; cp -a /etc/ufw "$d/etc-ufw" 2>/dev/null || true; echo "$d"; }
sysctl_harden(){ local fwd="$1" reason="$2"; [[ "$fwd" == yes ]] && val=1 || val=0; cat > "$SYSCTL_DROPIN" <<EOF
# Created by setup-ufw-zones-v11.sh
# $reason
net.ipv4.ip_forward = $val
net.ipv6.conf.all.forwarding = 0
net.ipv4.conf.all.accept_redirects = 0
net.ipv4.conf.default.accept_redirects = 0
net.ipv4.conf.all.send_redirects = 0
net.ipv4.conf.default.send_redirects = 0
net.ipv4.conf.all.rp_filter = 2
net.ipv4.conf.default.rp_filter = 2
net.ipv4.conf.all.log_martians = 1
net.ipv4.conf.default.log_martians = 1
EOF
run sysctl --system; }
ufw_base(){ run sed -i 's/^DEFAULT_FORWARD_POLICY=.*/DEFAULT_FORWARD_POLICY="DROP"/' /etc/default/ufw; run ufw --force reset; run ufw default deny incoming; run ufw default allow outgoing; run ufw default deny routed; run ufw logging high; }
allow_in(){ local i="$1" proto="$2" port="$3" comment="$4" srcs="$5" dsts="$6" s d; [[ -z "$srcs" ]] && srcs=any; [[ -z "$dsts" ]] && dsts=any; for s in $srcs; do for d in $dsts; do run ufw allow in on "$i" proto "$proto" from "$s" to "$d" port "$port" comment "$comment src=$s dst=$d"; done; done; }
route_in(){ local i="$1" proto="$2" port="$3" comment="$4" srcs="$5" dsts="$6" s d; [[ -z "$srcs" ]] && srcs=any; [[ -z "$dsts" ]] && return 0; for s in $srcs; do for d in $dsts; do run ufw route allow in on "$i" proto "$proto" from "$s" to "$d" port "$port" comment "$comment route src=$s dst=$d"; done; done; }
apply_ing(){ local i="$1" src="$2" dst="$3" specs="$4" label="$5" x proto port; for x in $specs; do proto="${x%%/*}"; port="${x#*/}"; allow_in "$i" "$proto" "$port" "$label $x inbound" "$src" "$dst"; [[ "$ROUTE_VIP" == yes ]] && route_in "$i" "$proto" "$port" "$label $x routed VIP" "$src" "$dst"; done; }
apply_cni(){ local i="$1" x p; case "$CNI_PROFILE" in canal-vxlan) for x in udp/8472 tcp/9099; do allow_in "$i" "${x%%/*}" "${x#*/}" "rke2 Canal $x inbound" "$K8S_NODE_SOURCES" ""; done;; canal-wireguard) for x in udp/8472 udp/51820 udp/51821 tcp/9099; do allow_in "$i" "${x%%/*}" "${x#*/}" "rke2 Canal/WireGuard $x inbound" "$K8S_NODE_SOURCES" ""; done;; calico-bgp) for p in 179 5473 9098 9099; do allow_in "$i" tcp "$p" "Calico port $p inbound" "$K8S_NODE_SOURCES" ""; done;; calico-vxlan) allow_in "$i" udp 4789 "Calico VXLAN inbound" "$K8S_NODE_SOURCES" "";; flannel-vxlan) allow_in "$i" udp 4789 "Flannel VXLAN inbound" "$K8S_NODE_SOURCES" "";; cilium-vxlan-wireguard) allow_in "$i" tcp 4240 "Cilium health inbound" "$K8S_NODE_SOURCES" ""; allow_in "$i" udp 8472 "Cilium VXLAN inbound" "$K8S_NODE_SOURCES" ""; allow_in "$i" udp 51871 "Cilium WireGuard inbound" "$K8S_NODE_SOURCES" "";; esac; }
apply_storage(){ local i="$1" o="${IFACE_STORAGE_OVERLAY[$1]}" p x; [[ "$o" =~ nfs ]] && allow_in "$i" tcp 2049 "storage_zone NFSv4 inbound" "$STORAGE_SOURCES" ""; [[ "$o" =~ iscsi ]] && allow_in "$i" tcp 3260 "storage_zone iSCSI target inbound" "$STORAGE_SOURCES" ""; [[ "$NFS_EXTRA_MODE" =~ udp ]] && allow_in "$i" udp 2049 "storage_zone NFS UDP inbound" "$STORAGE_SOURCES" ""; [[ "$o" == custom ]] && for x in $STORAGE_CUSTOM_SPECS; do allow_in "$i" "${x%%/*}" "${x#*/}" "storage custom $x inbound" "$STORAGE_SOURCES" ""; done; }
apply_all(){ local b f p x fwd=no; [[ ${#K8S_IFACES[@]} -gt 0 || ${#CONTOUR_IFACES[@]} -gt 0 ]] && fwd=yes; b="$(backup)"; sysctl_harden "$fwd" "UFW zone setup $SCRIPT_VERSION"; ufw_base; for f in "${ASSIGNED_IFACES[@]}"; do p=" ${IFACE_PROFILES[$f]:-} "; case "${IFACE_ZONE[$f]}" in domain_zone) allow_in "$f" tcp 22 "domain_zone SSH inbound" "$ADMIN_SOURCES" "";; storage_zone) apply_storage "$f";; esac; [[ "$p" == *" contour-envoy-ingress "* ]] && apply_ing "$f" "$VIP_SOURCES" "$VIP_DESTS" "$CONTOUR_SPECS" "Contour/Envoy ingress"; [[ "$p" == *" custom-ingress "* ]] && apply_ing "$f" "$VIP_SOURCES" "$VIP_DESTS" "$CUSTOM_INGRESS_SPECS" "custom ingress"; if contains "$f" "${K8S_VIP_IFACES[@]}" && [[ "$p" != *"contour-envoy-ingress"* && "$p" != *"custom-ingress"* ]]; then apply_ing "$f" "$VIP_SOURCES" "$VIP_DESTS" "tcp/80 tcp/443" "Kubernetes service/ingress VIP"; fi; if [[ "$p" == *" rke2-server "* ]]; then allow_in "$f" tcp 6443 "rke2-server API admin inbound" "$K8S_API_SOURCES" ""; allow_in "$f" tcp 6443 "rke2-server API node inbound" "$K8S_NODE_SOURCES" ""; allow_in "$f" tcp 9345 "rke2-server supervisor inbound" "$K8S_NODE_SOURCES" ""; for x in 2379 2380 2381; do allow_in "$f" tcp "$x" "rke2-server etcd/server-peer $x inbound" "$K8S_SERVER_PEER_SOURCES" ""; done; allow_in "$f" tcp 10250 "rke2-server kubelet inbound" "$K8S_NODE_SOURCES" ""; [[ "$CNI_PROFILE" != none ]] && apply_cni "$f"; fi; if [[ "$p" == *" rke2-agent "* ]]; then allow_in "$f" tcp 10250 "rke2-agent kubelet inbound" "$K8S_NODE_SOURCES" ""; [[ "$CNI_PROFILE" != none ]] && apply_cni "$f"; fi; if [[ "$p" == *" rke2-singlenode "* ]]; then allow_in "$f" tcp 6443 "rke2-singlenode API inbound" "$K8S_API_SOURCES" ""; [[ "$SINGLENODE_ENABLE_CNI" == yes && "$CNI_PROFILE" != none ]] && apply_cni "$f"; fi; [[ "$NODEPORTS" == yes ]] && { allow_in "$f" tcp 30000:32767 "Kubernetes NodePort TCP inbound" "$VIP_SOURCES" ""; allow_in "$f" udp 30000:32767 "Kubernetes NodePort UDP inbound" "$VIP_SOURCES" ""; }; [[ "$KUBE_PROXY_HEALTHCHECK" == yes ]] && allow_in "$f" tcp 10256 "kube-proxy health check inbound" "$K8S_LB_HEALTHCHECK_SOURCES" ""; done; for f in "${ASSIGNED_IFACES[@]}"; do for x in "${ASSIGNED_IFACES[@]}"; do [[ "$f" != "$x" ]] && run ufw route deny in on "$f" out on "$x" comment "deny routed traffic $f to $x"; done; done; run ufw --force enable; run ufw reload; ufw status numbered; echo "Backup saved at: $b"; }

main(){ init_colors; need_root; init_log; for c in ip ufw sysctl awk sed ss iptables; do need "$c"; done; heading "=== UFW Interface Zone/Profile Setup ==="; echo "Version: $SCRIPT_VERSION"; discover; if ! maybe_import; then collect; fi; rebuild; show_plan; step "Optional configuration save"; yesno "Save this configuration to a file before applying?" Y && save_config; yesno "Apply this firewall configuration now?" N || { echo "No changes applied. Action log saved at: $LOG_FILE"; exit 0; }; apply_all; }
main "$@"
